import * as React from "react";

import { Checkbox } from "../checkbox";
import CheckIcon from "../icons/CheckIcon";
import { Popover, PopoverContent, PopoverTrigger } from "../popover";
import { SearchInput } from "../search-input";
import { cn } from "../utils/cn";

type MenuItem = {
  id: string;
  label: string;
  icon?: React.ReactNode;
  disabled?: boolean;
};

type MenuGroup = {
  label?: string;
  items: MenuItem[];
};

type MenuProps = {
  trigger: React.ReactNode;
  groups: MenuGroup[];
  selected?: string | string[];
  onSelect?: (id: string) => void;
  multiple?: boolean;
  searchable?: boolean;
  searchPlaceholder?: string;
  className?: string;
};

function isSelected(
  id: string,
  selected: string | string[] | undefined,
): boolean {
  if (selected === undefined) return false;
  if (Array.isArray(selected)) return selected.includes(id);
  return selected === id;
}

/**
 * Enhanced dropdown with search, single/multi select, and subheaders.
 *
 * Wraps Popover for full control over content layout. Supports grouped
 * items, inline search filtering, and both single and multi-select modes.
 */
function Menu({
  trigger,
  groups,
  selected,
  onSelect,
  multiple = false,
  searchable = false,
  searchPlaceholder = "Search...",
  className,
}: MenuProps) {
  const [search, setSearch] = React.useState("");
  const [open, setOpen] = React.useState(false);

  const filteredGroups = React.useMemo(() => {
    if (!search) return groups;
    const lower = search.toLowerCase();
    return groups
      .map((group) => ({
        ...group,
        items: group.items.filter((item) =>
          item.label.toLowerCase().includes(lower),
        ),
      }))
      .filter((group) => group.items.length > 0);
  }, [groups, search]);

  function handleSelect(id: string) {
    onSelect?.(id);
    if (!multiple) {
      setOpen(false);
    }
  }

  // Reset search when popover closes
  React.useEffect(() => {
    if (!open) {
      setSearch("");
    }
  }, [open]);

  return (
    <Popover open={open} onOpenChange={setOpen}>
      <PopoverTrigger asChild data-slot="menu">
        {trigger}
      </PopoverTrigger>
      <PopoverContent
        align="start"
        sideOffset={4}
        className={cn("w-56 p-0", className)}
      >
        <div data-slot="menu-content" className="flex flex-col">
          {searchable && (
            <div data-slot="menu-search" className="p-2 border-b">
              <SearchInput
                placeholder={searchPlaceholder}
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                onClear={() => setSearch("")}
              />
            </div>
          )}
          <div
            data-slot="menu-items"
            className="max-h-60 overflow-y-auto py-1"
            role="listbox"
            aria-multiselectable={multiple || undefined}
          >
            {filteredGroups.map((group, groupIndex) => (
              <React.Fragment key={group.label ?? `group-${groupIndex}`}>
                {groupIndex > 0 && (
                  <div
                    data-slot="menu-separator"
                    className="-mx-0 my-1 h-px bg-border-muted"
                  />
                )}
                {group.label && (
                  <div
                    data-slot="menu-group-label"
                    className="px-3 py-1.5 text-xs font-semibold text-muted-foreground uppercase tracking-wide"
                  >
                    {group.label}
                  </div>
                )}
                {group.items.map((item) => {
                  const active = isSelected(item.id, selected);
                  return (
                    <button
                      key={item.id}
                      type="button"
                      role="option"
                      aria-selected={active}
                      aria-disabled={item.disabled || undefined}
                      disabled={item.disabled}
                      data-slot="menu-item"
                      className={cn(
                        "flex w-full cursor-default select-none items-center gap-2 rounded-sm px-3 py-1.5 text-sm outline-none transition-colors",
                        "hover:bg-surface hover:text-foreground",
                        "focus-visible:bg-surface focus-visible:text-foreground",
                        "disabled:pointer-events-none disabled:opacity-50",
                        active && !multiple && "text-primary",
                      )}
                      onClick={() => handleSelect(item.id)}
                    >
                      {multiple && (
                        <Checkbox
                          checked={active}
                          tabIndex={-1}
                          aria-hidden="true"
                          className="pointer-events-none"
                        />
                      )}
                      {item.icon && (
                        <span
                          data-slot="menu-item-icon"
                          className="flex shrink-0 items-center"
                        >
                          {item.icon}
                        </span>
                      )}
                      <span className="flex-1 truncate text-left">
                        {item.label}
                      </span>
                      {!multiple && active && (
                        <CheckIcon className="ml-auto size-4 shrink-0" />
                      )}
                    </button>
                  );
                })}
              </React.Fragment>
            ))}
            {filteredGroups.length === 0 && (
              <div
                data-slot="menu-empty"
                className="px-3 py-6 text-center text-sm text-muted-foreground"
              >
                No results found
              </div>
            )}
          </div>
        </div>
      </PopoverContent>
    </Popover>
  );
}

export { Menu };
export type { MenuItem, MenuGroup, MenuProps };
